:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Blog – WordPress.org Brasil\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"https://br.wordpress.org\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"width\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:6:\"height\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}s:4:\"item\";a:10:{i:0;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"WordPress 7.0 Release Candidate 2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"https://br.wordpress.org/2026/03/26/wordpress-7-0-release-candidate-2/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 26 Mar 2026 19:06:56 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"7.0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3467\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:357:\"O segundo Release Candidate (“RC2”) para WordPress 7.0 está pronto para baixar e testar! Esta versão do software WordPress está em desenvolvimento. Não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica. Em vez disso, recomenda-se avaliar o RC2 em um servidor e site de testes. Alcançar esta [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"Andre\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:9105:\"\n<p class=\"wp-block-paragraph\">O segundo Release Candidate (“RC2”) para WordPress 7.0 está pronto para baixar e testar!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Esta versão do software WordPress está em desenvolvimento</strong>. <strong>Não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica.</strong> Em vez disso, recomenda-se avaliar o RC2 em um servidor e site de testes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Alcançar esta fase do ciclo de lançamento é um marco importante. Embora os Release Candidates sejam considerados prontos para lançamento, os testes continuam sendo cruciais para garantir que tudo no WordPress 7.0 seja o melhor possível.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Você pode testar o WordPress 7.0 RC2 de quatro maneiras:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>Plugin</strong></td><td>Instale e ative o plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> em uma instalação do WordPress. (Selecione o canal “Bleeding edge” e “Beta/RC Only” stream.)</td></tr><tr><td><strong>Baixe diretamente</strong></td><td>Baixe a <a href=\"https://wordpress.org/wordpress-7.0-RC2.zip\">versão RC2 (zip)</a> e instale-a em um site WordPress.</td></tr><tr><td><strong>Linha de Comando</strong></td><td>Use este comando do <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a>:<br><code>wp core update --version=7.0-</code>RC2</td></tr><tr><td><strong>WordPress Playground</strong></td><td>Use uma <a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\">instância do WordPress Playground</a> para testar o software diretamente no seu navegador. Nenhuma configuração é necessária, basta clicar e testar!</td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\">A data de lançamento final programada para o WordPress 7.0 é <strong>9 de abril de 2026</strong>. O cronograma de lançamento completo <a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">pode ser encontrado aqui</a>. Sua ajuda para testar versões Beta e RC é vital para tornar esta versão o mais estável e poderosa possível. Agradecemos a todos que ajudam com os testes!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Continue conferindo o blog <a href=\"https://make.wordpress.org/core/\">Make WordPress Core</a> para <a href=\"https://make.wordpress.org/core/tag/7-0\">posts relacionados a versão 7.0</a> nas próximas semanas para obter mais informações.</p>\n\n\n\n<h2 class=\"wp-block-heading\">O que há no WordPress 7.0 RC2?</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>O que há de novo no WordPress 7.0</strong>? Confira o <a href=\"https://br.wordpress.org/2026/02/20/wordpress-7-0-beta-1/\">anúncio do Beta 1</a> e <a href=\"https://make.wordpress.org/core/tag/dev-notes+7-0/\">o Developer Notes da versão 7.0</a> (em inglês) para detalhes e destaques. Para informações técnicas relacionadas a questões abordadas desde a versão <a href=\"https://br.wordpress.org/2026/03/24/wordpress-7-0-release-candidate-1/\">RC1,</a> você pode navegar pelos seguintes links:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/7.0?since=2026-03-24&amp;until=2026-03-26\">Tíquetes do GitHub</a> desde 24 de março de 2026</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=03%2F24%2F2026..03%2F26%2F2026&amp;milestone=7.0&amp;group=component&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Tíquetes fechados do Trac</a> desde 24 de março de 2026</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Como você pode contribuir</h2>\n\n\n\n<p class=\"wp-block-paragraph\">O WordPress é um software de código aberto possibilitado por uma comunidade apaixonada de pessoas que colaboram e contribuem para o seu desenvolvimento. Os recursos abaixo descrevem várias maneiras de ajudar a plataforma web de código aberto mais popular do mundo, independentemente de sua experiência técnica.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Envolva-se em testes</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Testar problemas é crucial para o desenvolvimento de qualquer software. É também uma forma significativa de qualquer pessoa contribuir.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Sua ajuda para testar a versão do WordPress 7.0 RC2 é fundamental para garantir que a versão final seja a melhor possível. Embora testar o processo de atualização seja essencial, experimentar novos recursos é igualmente importante. Este <a href=\"https://make.wordpress.org/test/2026/02/20/help-test-wordpress-7-0/\">guia detalhado</a> irá orientá-lo através de recursos de teste no WordPress 7.0. Para aqueles que são novos em testes, siga <a href=\"https://make.wordpress.org/test/handbook/get-setup-for-testing/\">este guia geral</a> para obter mais detalhes sobre como configurar os testes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">O que mais testar:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/test/2026/03/11/its-time-to-test-real-time-collaboration/\">Colaboração em tempo real</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/test/2026/02/27/call-for-testing-pattern-editing-and-content-only-interactivity-in-wordpress-7-0/\">Edição de Padrões e Interatividade somente de conteúdo</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Se você encontrar um problema, por favor, compre-o para <a href=\"https://wordpress.org/support/forum/alphabeta/\">a área Alpha /</a> Beta dos fóruns de suporte ou diretamente <a href=\"https://core.trac.wordpress.org/newticket\">para o WordPress</a> Trac, se você estiver confortável escrevendo um relatório de bugs reproduzível. Você também pode verificar seu problema contra uma lista de <a href=\"https://core.trac.wordpress.org/tickets/major\">bugs conhecidos</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Curioso sobre os lançamentos de testes em geral? Acompanhe as <a href=\"https://make.wordpress.org/test/\">iniciativas de teste no Make Core</a> e <a href=\"https://wordpress.slack.com/messages/core-test/\">junte-se</a> ao <a href=\"https://wordpress.slack.com/messages/core-test/\">canal #core-test</a> no <a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Teste em suas plataformas de hospedagem</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Os hosts da Web fornecem infraestrutura vital para o suporte ao WordPress e seus usuários. O teste em sistemas de hospedagem ajuda a informar o processo de desenvolvimento, garantindo que o WordPress e as plataformas de hospedagem sejam totalmente compatíveis, livres de erros, otimizados para a melhor experiência possível do usuário e que as atualizações sejam implementadas para sites de clientes sem problemas.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Quer testar o WordPress no seu sistema de hospedagem? <a href=\"https://make.wordpress.org/hosting/test-results-getting-started/\">Comece a configurar testes de hospedagem distribuída aqui</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Atualize seu tema ou plugin</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Para autores de plugins e temas, seus produtos desempenham um papel integral na extensão da funcionalidade e do valor do WordPress para todos os usuários.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Agradecemos por continuar a testar seus temas e plugins com os lançamentos beta do WordPress 7.0. Com o RC2, você irá concluir seus testes e atualizar a versão <em>“Tested up to”</em> no <a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\">arquivo readme do seu plugin</a> para <code>7.0</code>. Se você encontrar problemas de compatibilidade, publique informações detalhadas no <a href=\"https://wordpress.org/support/forum/alphabeta/\">fórum de suporte</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Curioso sobre os lançamentos de testes em geral? Acompanhe as <a href=\"https://make.wordpress.org/test/\">iniciativas de testes</a> e participe do canal <a href=\"https://wordpress.slack.com/messages/core-test/\">#core-test</a> no <a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Traduza o WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://translate.wordpress.org/projects/wp/dev/pt-br/default/\">Ajude-nos a traduzir o WordPress para o português!</a>&nbsp;O lançamento dessa versão também significa que&nbsp;<a href=\"https://make.wordpress.org/polyglots/handbook/glossary/#hard-freeze\">novas strings para a tradução</a>&nbsp;da versão 7.0 serão evitadas.</p>\n\n\n\n<p class=\"has-text-align-right wp-block-paragraph\"><em>Agradecemos a <a href=\"https://profiles.wordpress.org/amykamala/\">@amykamala</a> e </em><a href=\"https://profiles.wordpress.org/annezazu/\">@annezazu</a> <em>pela colaboração no <a href=\"https://wordpress.org/news/2026/03/wordpress-7-0-release-candidate-2/\">post original</a>.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3467\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"WordPress 7.0 Release Candidate 1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"https://br.wordpress.org/2026/03/24/wordpress-7-0-release-candidate-1/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 24 Mar 2026 19:33:39 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"7.0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3462\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:351:\"O primeiro Release Candidate (“RC1”) para WordPress 7.0 está pronto para baixar e testar! Esta versão do software WordPress ainda está em desenvolvimento. Não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica. Em vez disso, recomenda-se avaliar o RC1 em um servidor e site de testes. O [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"Andre\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:11763:\"\n<p class=\"wp-block-paragraph\">O primeiro Release Candidate (“RC1”) para WordPress 7.0 está pronto para baixar e testar!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Esta versão do software WordPress ainda está em desenvolvimento</strong>. Não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica. Em vez disso, recomenda-se avaliar o RC1 em um servidor e site de testes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">O WordPress 7.0 RC1 pode ser testado usando qualquer um dos seguintes métodos:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>Plugin</strong></td><td>Instale e ative o plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> em uma instalação do WordPress. (Selecione o canal “Bleeding edge” e “Beta/RC Only” stream.)</td></tr><tr><td><strong>Baixe diretamente</strong></td><td>Baixe a <a href=\"https://wordpress.org/wordpress-7.0-RC1.zip\">versão RC1 (zip)</a> e instale-a em um site WordPress.</td></tr><tr><td><strong>Linha de Comando</strong></td><td>Use este comando do  <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a>:<br><code>wp core update --version=7.0-RC1</code></td></tr><tr><td><strong>WordPress Playground</strong></td><td>Use uma <a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\">instância do WordPress Playground</a> para testar o software diretamente no seu navegador. Nenhuma configuração é necessária – basta clicar e testar!</td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\">A data de lançamento final programada para o WordPress 7.0 é <strong>9 de abril de 2026</strong>. O cronograma de lançamento completo <a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">pode ser encontrado aqui</a>. Sua ajuda para testar versões Beta e RC é vital para tornar esta versão o mais estável e poderosa possível. Agradecemos a todos que ajudam com os testes!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Continue conferindo o blog <a href=\"https://make.wordpress.org/core/\">Make WordPress Core</a> para <a href=\"https://make.wordpress.org/core/tag/7-0\">posts relacionados a versão 7.0</a>  nas próximas semanas para obter mais informações.</p>\n\n\n\n<h2 class=\"wp-block-heading\">O que há no WordPress 7.0 RC1?</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>O que há de novo no WordPress 7.0?</strong> Confira o <a href=\"https://br.wordpress.org/2026/02/20/wordpress-7-0-beta-1/\">anúncio da versão Beta 1</a> e <a href=\"https://make.wordpress.org/core/tag/dev-notes+7-0/\">o WordPress 7.0 Developer Notes</a> para detalhes e destaques.</p>\n\n\n\n<p class=\"wp-block-paragraph\">A versão RC1 contém mais de 267 atualizações e correções desde a versão do Beta 5. Você pode navegar pelos detalhes técnicos para todas as questões abordadas desde o Beta 5 usando esses links:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/7.0?since=2026-03-12&amp;until=2026-03-24\">Tíquetes do GitHub</a> desde 12 de março de 2026</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=03%2F12%2F2026..03%2F24%2F2026&amp;milestone=7.0&amp;group=component&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Tíquetes fechados do Trac</a> desde 12 de março de 2026</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/7.0?since=2026-03-19&amp;until=2026-03-24\">Tíquetes do Github</a> desde 19 de março de 2026</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=03%2F19%2F2026..03%2F24%2F2026&amp;milestone=7.0&amp;group=component&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Tíquetes fechados do Trac</a> desde 19 de março de 2026</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Quer analisar mais profundamente os detalhes e as notas técnicas para este lançamento? Esses tíquetes e pull requests são apenas algumas das últimas atualizações:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/76700\">#76700</a> : Processamento de mídia client site somente pelo plugin Gutemberg</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/76722\">#76722</a> : Adicionado suporte para provedores não-IA na tela do conector</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/76736\">#76736</a> : Novo hook de ativação para habilitar o RTC por padrão</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64904\">#64904</a> : Constante <code>WP_ALLOW_COLLABORATION</code> para RTC</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/76704\">#76704</a> : Aumento dos intervalos de sincronização para RTC</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/76643\">#76643</a> : Colaboração em tempo real habilitado por padrão</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/76460\">#76460</a> : Alterne para ativar/desativar as notificações da sessão do RTC</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/changeset/62046\">#62046</a> : Atualizado o pacote PHP AI Client para 1.3.1</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/76550\">#76550</a> : Revisões: Mostrar atributos de bloco alterados na barra lateral</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/changeset/62067\">#62067</a> : Opção de configuração para desativar todos os recursos de LLM</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/63697\">#63697</a> : OPCache adicionado em <code>Diagnóstico &gt; Informações &gt; Servidor</code></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Introduzido durante o Beta:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/75757\">#75757</a> : Atalho da paleta de comandos</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64730\">#64730</a> : Tela de conectores de IA</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64791\">#64791</a> : API de conectores: API de extensibilidade para tela de conectores</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>O lançamento final está a caminho de 9 de abril de 2026.</strong> Como sempre, uma versão bem-sucedida depende dos testes da comunidade. Então, baixe e teste!</p>\n\n\n\n<h2 class=\"wp-block-heading\">Como você pode contribuir</h2>\n\n\n\n<p class=\"wp-block-paragraph\">O WordPress é um software de código aberto possibilitado por uma comunidade apaixonada de pessoas que colaboram e contribuem para o seu desenvolvimento. Os recursos abaixo descrevem várias maneiras de ajudar a plataforma web de código aberto mais popular do mundo, independentemente de sua experiência técnica.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Ajude a testar esta versão</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Testar problemas é crucial para o desenvolvimento de qualquer software. É também uma forma significativa de qualquer pessoa contribuir. Sua ajuda para testar a versão do WordPress 7.0 RC1 é fundamental para garantir que a versão final seja a melhor possível. Embora testar o processo de atualização seja essencial, experimentar novos recursos é igualmente importante. Este <a href=\"https://make.wordpress.org/test/2026/02/20/help-test-wordpress-7-0/\">guia detalhado</a> irá orientá-lo através de recursos de teste no WordPress 7.0.</p>\n\n\n\n<p class=\"wp-block-paragraph\">O que testar:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/test/2026/03/11/its-time-to-test-real-time-collaboration/\">Colaboração em tempo real</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/test/2026/02/27/call-for-testing-pattern-editing-and-content-only-interactivity-in-wordpress-7-0/\">Edição de padrões e interatividade em conteúdo</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Se você encontrar um problema, compartilhe-o na <a href=\"https://wordpress.org/support/forum/alphabeta/\">área Alpha/Beta</a> dos fóruns de suporte ou diretamente <a href=\"https://core.trac.wordpress.org/newticket\">para o WordPress Trac</a>, se você estiver confortável escrevendo um relatório de erros reproduzível. Você também pode verificar seu problema em uma lista de <a href=\"https://core.trac.wordpress.org/tickets/major\">erros conhecidos</a>. Curioso sobre os lançamentos de testes em geral? Acompanhe as <a href=\"https://make.wordpress.org/test/\">iniciativas de teste no Make Core</a> e junte-se ao <a href=\"https://wordpress.slack.com/messages/core-test/\">canal #core-test</a> no <a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Teste em suas plataformas de hospedagem</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Os sistemas de hospedagem fornecem infraestrutura vital para suportar o WordPress e seus usuários. O teste na infraestrutura de hospedagem garante que o WordPress e os sistemas de hospedagem sejam totalmente compatíveis, livres de erros, otimizados para a melhor experiência possível do usuário e que as atualizações sejam lançadas para sites de clientes sem problemas. Agradecemos a todos os <a href=\"https://make.wordpress.org/hosting/test-results/\">anfitriões da web que testam o WordPress!</a></p>\n\n\n\n<p class=\"wp-block-paragraph\">Quer configurar testes em seu sistema de hospedagem? <a href=\"https://make.wordpress.org/hosting/test-results-getting-started/\">Comece a configurar os testes infraestrutura distribuída aqui</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Atualize seu tema ou plugin</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Para autores de plugins e temas, seus produtos desempenham um papel integral na extensão da funcionalidade e do valor do WordPress para todos os usuários.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Agradecemos por continuar a testar seus temas e plugins com os lançamentos beta do WordPress 7.0. Com o RC1, você irá concluir seus testes e atualizar a versão <em>“Tested up to”</em> no <a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\">arquivo readme do seu plugin</a> para <code>7.0</code>. Se você encontrar problemas de compatibilidade, publique informações detalhadas no <a href=\"https://wordpress.org/support/forum/alphabeta/\">fórum de suporte</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Curioso sobre os lançamentos de testes em geral? Acompanhe as <a href=\"https://make.wordpress.org/test/\">iniciativas de testes</a> e participe do canal <a href=\"https://wordpress.slack.com/messages/core-test/\">#core-test</a> no <a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Traduza o WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://translate.wordpress.org/projects/wp/dev/pt-br/default/\">Ajude-nos a traduzir o WordPress para o português!</a> O lançamento dessa versão também significa que <a href=\"https://make.wordpress.org/polyglots/handbook/glossary/#hard-freeze\">novas strings para a tradução</a> da versão 7.0 serão evitadas.</p>\n\n\n\n<p class=\"has-text-align-right wp-block-paragraph\"><em>Agradecemos a <a href=\"https://profiles.wordpress.org/4thhubbard/\">@4thhubbard</a>, <a href=\"https://profiles.wordpress.org/desrosj/\">@desrosj</a>, <a href=\"https://profiles.wordpress.org/jeffpaul/\">@jeffpaul</a>, <a href=\"https://profiles.wordpress.org/chaion07/\">@chaion07</a> e <a href=\"https://profiles.wordpress.org/audrasjb/\">@audrasjb</a> pela colaboração e revisão do <a href=\"https://wordpress.org/news/2026/03/wordpress-7-0-release-candidate-1/\">post original</a>.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3462\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:70:\"\n		\n		\n					\n		\n		\n		\n				\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"Conecte agentes de código de IA ao WordPress Playground usando o MCP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:105:\"https://br.wordpress.org/2026/03/17/conecte-agentes-de-codigo-de-ia-ao-wordpress-playground-usando-o-mcp/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:113:\"https://br.wordpress.org/2026/03/17/conecte-agentes-de-codigo-de-ia-ao-wordpress-playground-usando-o-mcp/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 17 Mar 2026 11:39:46 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3452\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:385:\"Se o seu agente de programação pudesse ler arquivos do WordPress, executar PHP e gerenciar sites diretamente no seu navegador? O pacote @wp-playground/mcp conecta agentes de código de IA e uma instância do Playground baseada no navegador através do Model Context Protocol (MCP). Execute um comando para conectar. Nenhuma configuração é necessária no Playground. Como [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Fellyph Cintra\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8980:\"\n<p class=\"wp-block-paragraph\">Se o seu agente de programação pudesse ler arquivos do WordPress, executar PHP e gerenciar sites diretamente no seu navegador? O pacote <code>@wp-playground/mcp</code> conecta agentes de código de IA e uma instância do Playground baseada no navegador através do <em>Model Context Protocol</em> (MCP). Execute um comando para conectar. Nenhuma configuração é necessária no Playground.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Como funciona</h2>\n\n\n\n<p class=\"wp-block-paragraph\">O servidor MCP roda como um processo local do Node.js utilizando o transporte <code>stdio</code>. O seu cliente de IA se comunica diretamente com ele, e o servidor encaminha os comandos para uma instância do Playground rodando no seu navegador por meio de uma conexão WebSocket.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Cliente de IA (stdio) &#8211;&gt; Servidor MCP (Node.js) &#8211;&gt; WebSocket &#8211;&gt; Navegador (Playground)</p>\n\n\n\n<p class=\"wp-block-paragraph\">Quando você abre o Playground no seu navegador, um WebSocket conecta a aba do navegador ao servidor MCP. O servidor atribui uma porta local aleatória na inicialização e a repassa para o navegador através do parâmetro de URL <code>mcp-port</code>. O servidor traduz as chamadas de ferramentas (tool calls) do seu agente em ações diretas no Playground: leitura de arquivos, execução de PHP e navegação pelas páginas.</p>\n\n\n\n<p class=\"wp-block-paragraph\">A conexão permanece local na sua máquina. Restrições de origem e autenticação baseada em tokens na inicialização evitam o acesso não autorizado de outros sites e extensões do navegador.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Configure o servidor MCP</h2>\n\n\n\n<h3 class=\"wp-block-heading\">Claude Code</h3>\n\n\n<div class=\"wp-block-syntaxhighlighter-code \"><pre class=\"brush: plain; title: ; notranslate\">\nclaude mcp add --transport stdio --scope user wordpress-playground -- npx -y @wp-playground/mcp\n</pre></div>\n\n\n<p class=\"wp-block-paragraph\">A flag <code>--scope user</code> torna o servidor disponível em todos os seus projetos. Use <code>--scope local</code> para restringi-lo apenas ao projeto atual.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Gemini CLI</h3>\n\n\n<div class=\"wp-block-syntaxhighlighter-code \"><pre class=\"brush: plain; title: ; notranslate\">\ngemini mcp add wordpress-playground npx -y @wp-playground/mcp\n</pre></div>\n\n\n<p class=\"wp-block-paragraph\">O transporte padrão é o <code>stdio</code>. Use <code>-s user</code> para um escopo de nível de usuário.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Configuração JSON</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Você também pode configurar o servidor manualmente. Adicione o seguinte código ao seu <code>.mcp.json</code> (Claude Code / Claude Desktop):</p>\n\n\n<div class=\"wp-block-syntaxhighlighter-code \"><pre class=\"brush: plain; title: ; notranslate\">\n{\n  &quot;mcpServers&quot;: {\n    &quot;wordpress-playground&quot;: {\n      &quot;type&quot;: &quot;stdio&quot;,\n      &quot;command&quot;: &quot;npx&quot;,\n      &quot;args&quot;: &#x5B;&quot;-y&quot;, &quot;@wp-playground/mcp&quot;]\n    }\n  }\n}\n</pre></div>\n\n\n<p class=\"wp-block-paragraph\">A Gemini CLI usa a mesma estrutura no arquivo <code>settings.json</code>, mas sem o campo <code>\"type\"</code>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Após a configuração, abra o Playground no seu navegador. O agente fornecerá a URL exata assim que se conectar.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Três fluxos de trabalho práticos</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Depois de conectado, o seu agente gerencia o WordPress através de linguagem natural.</p>\n\n\n\n<h3 class=\"wp-block-heading\">1. Instalar, testar e fazer o build de um plugin</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Peça ao seu agente para instalar e verificar um plugin sem precisar tocar no painel de administração do WordPress:</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">&#8220;Instale o plugin Classic Editor no meu site do Playground e confirme se ele desativa o editor de blocos.&#8221;</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">O agente utiliza o <code>playground_execute_php</code> para chamar a função <code>wp_remote_get</code>, baixar o arquivo zip do plugin e extraí-lo para a pasta <code>wp-content/plugins/</code>. Em seguida, ele ativa o plugin usando <code>activate_plugin()</code> e dispara o <code>playground_request</code> na URL do editor de postagens para confirmar que a interface clássica foi carregada. Você consegue ver cada etapa no <em>output</em> (saída) do seu agente.</p>\n\n\n\n<h3 class=\"wp-block-heading\">2. Depurar opções do site com PHP</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Precisa verificar o que um plugin salvou no banco de dados? Pule a interface do admin e faça uma consulta (query) diretamente na tabela <code>wp_options</code>:</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">&#8220;Mostre-me todas as opções carregadas automaticamente (autoloaded) que contenham &#8216;woocommerce&#8217; no nome da opção.&#8221;</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">O agente executa o <code>playground_execute_php</code> com um script curto:</p>\n\n\n<div class=\"wp-block-syntaxhighlighter-code \"><pre class=\"brush: plain; title: ; notranslate\">\nglobal $wpdb;\n$results = $wpdb-&amp;gt;get_results(\n    &quot;SELECT option_name, option_value FROM $wpdb-&amp;gt;options WHERE option_name LIKE &#039;%woocommerce%&#039;&quot;\n);\nprint_r($results);\n</pre></div>\n\n\n<p class=\"wp-block-paragraph\">O Playground usa SQLite em vez de MySQL, portanto, evite usar valores de coluna específicos do MySQL nas suas consultas. A abstração do <code>$wpdb</code> cuida da tradução, mas condições de filtro como <code>autoload = \'yes\'</code> podem não retornar os resultados esperados.</p>\n\n\n\n<p class=\"wp-block-paragraph\">A saída aparece diretamente na sua conversa. Não é necessário usar o phpMyAdmin ou qualquer outro cliente de banco de dados.</p>\n\n\n\n<h3 class=\"wp-block-heading\">3. Criar a estrutura de arquivos de um tema</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Construir um tema filho (<em>child theme</em>) do zero envolve criar diretórios, escrever arquivos de template e registrar o tema. Deixe o agente cuidar de todo esse código base (<em>boilerplate</em>):</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">&#8220;Crie um tema filho (child theme) do Twenty Twenty-Five chamado &#8216;Studio Child&#8217; com um template part de cabeçalho personalizado e um template de página inicial (front-page).&#8221;</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">O agente chama a ferramenta <code>playground_mkdir</code> para criar o diretório do tema, a <code>playground_write_file</code> para gerar o <code>style.css</code>, o <code>theme.json</code> e os arquivos de template, e depois usa a <code>playground_execute_php</code> para verificar se o tema aparece no painel de administração. Se um arquivo contiver algum erro, o agente faz a leitura dele com a <code>playground_read_file</code> e corrige o erro na etapa seguinte.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Ferramentas disponíveis</h2>\n\n\n\n<p class=\"wp-block-paragraph\">O servidor MCP expõe <a href=\"https://www.npmjs.com/package/@wp-playground/mcp#available-tools\">estas ferramentas ao seu agente</a>:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Gerenciamento de sites</strong>: <code>playground_get_website_url</code>, <code>playground_list_sites</code>, <code>playground_open_site</code>, <code>playground_rename_site</code>, <code>playground_save_site</code></li>\n\n\n\n<li><strong>Execução de código</strong>: <code>playground_execute_php</code>, <code>playground_request</code></li>\n\n\n\n<li><strong>Navegação</strong>: <code>playground_navigate</code>, <code>playground_get_current_url</code>, <code>playground_get_site_info</code></li>\n\n\n\n<li><strong>Sistema de arquivos</strong>: <code>playground_read_file</code>, <code>playground_write_file</code>, <code>playground_list_files</code>, <code>playground_mkdir</code>, <code>playground_delete_file</code>, <code>playground_delete_directory</code>, <code>playground_file_exists</code></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Compartilhe seu feedback</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Experimente o pacote <code>@wp-playground/mcp</code> e conte-nos o que você construiu. Compartilhe sua experiência no canal <strong>#playground</strong> no <a href=\"https://make.wordpress.org/chat/\">Making WordPress Slack</a> ou abra uma <em>issue</em> no<a href=\"https://github.com/WordPress/wordpress-playground/issues\">GitHub</a> para sugerir novas ferramentas.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Props</em> (agradecimentos) a <a href=\"https://profiles.wordpress.org/berislavgrgicak/\">@berislavgrgicak</a> por criar o servidor MCP e revisar o post original.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:110:\"https://br.wordpress.org/2026/03/17/conecte-agentes-de-codigo-de-ia-ao-wordpress-playground-usando-o-mcp/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3452\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"WordPress 7.0 Beta 5\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://br.wordpress.org/2026/03/12/wordpress-7-0-beta-5/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:65:\"https://br.wordpress.org/2026/03/12/wordpress-7-0-beta-5/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 12 Mar 2026 16:19:11 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"7.0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3446\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:332:\"O WordPress 7.0 Beta 5 já está pronto para baixar e testar! Esta versão do software WordPress ainda está em desenvolvimento. Não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica. Em vez disso, recomenda-se testar o Beta 5 em um servidor e sites de teste. WordPress 7.0 [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"Andre\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6941:\"\n<p class=\"wp-block-paragraph\">O WordPress 7.0 Beta 5 já está pronto para baixar e testar!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Esta versão do software WordPress ainda está em desenvolvimento</strong>. Não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica. Em vez disso, recomenda-se testar o Beta 5 em um servidor e sites de teste.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0 Beta 5 pode ser testado usando qualquer um dos seguintes métodos:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>Plugin</strong></td><td>Instale e ative o plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> em uma instalação do WordPress. (Selecione o canal “Bleeding edge” e “Beta/RC Only” stream.)</td></tr><tr><td><strong>Baixe diretamente</strong></td><td>Baixe a <a href=\"https://wordpress.org/wordpress-7.0-beta5.zip\">versão Beta 5 (zip)</a> e instale-a em um site WordPress.</td></tr><tr><td><strong>Linha de Comando</strong></td><td>Use este comando do <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a>:<br><code>wp core update --version=7.0-beta</code>5</td></tr><tr><td><strong>WordPress Playground</strong></td><td>Use uma <a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\">instância do WordPress Playground</a> para testar o software diretamente no seu navegador. Nenhuma configuração é necessária, basta clicar e testar!</td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\">A data de lançamento final programada para o WordPress 7.0 ainda é <strong>9 de abril de 2026</strong>. O <a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">cronograma de lançamento</a> completo pode ser encontrado <a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">aqui</a>. Sua ajuda para testar versões Beta e RC é vital para tornar esta versão o mais estável e poderosa possível. Agradecemos a todos que ajudam com os testes!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Continue acompanhando o <a href=\"https://make.wordpress.org/core/\">blog Make WordPress Core</a> para <a href=\"https://make.wordpress.org/core/tag/7-0\">posts relacionados a versão 7.0</a> nas próximas semanas para obter mais informações.</p>\n\n\n\n<h2 class=\"wp-block-heading\">O que há de novo no WordPress 7.0?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Confira os anúncios das versões <a href=\"https://br.wordpress.org/2026/02/20/wordpress-7-0-beta-1/\">Beta 1</a>, <a href=\"https://br.wordpress.org/2026/02/26/wordpress-7-0-beta-2/\">Beta 2</a>, <a href=\"https://br.wordpress.org/2026/03/05/wordpress-7-0-beta-3/\">Beta 3</a> e <a href=\"https://br.wordpress.org/2026/03/10/wordpress-6-9-3-e-7-0-beta-4/\">Beta 4</a> para detalhes e destaques.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Como testar esta versão</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Sua ajuda testando o WordPress 7.0 Beta 5 é fundamental para garantir que tudo na versão seja o melhor possível. Embora testar o processo de atualização seja essencial, experimentar novos recursos é igualmente importante. Este <a href=\"https://make.wordpress.org/test/2026/02/20/help-test-wordpress-7-0/\">guia sobre o que testar no WordPress 7</a> irá guiá-lo através de recursos de teste na versão 7.0.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Se você encontrar um problema, compartilhe-o na&nbsp;<a href=\"https://wordpress.org/support/forum/alphabeta/\">área Alpha/Beta</a>&nbsp;dos fóruns de suporte ou diretamente&nbsp;<a href=\"https://core.trac.wordpress.org/newticket\">para o WordPress Trac</a>, se você estiver confortável escrevendo um relatório de erros reproduzível. Você também pode verificar seu problema em uma lista de&nbsp;<a href=\"https://core.trac.wordpress.org/tickets/major\">erros conhecidos</a>. Curioso sobre os lançamentos de testes em geral? Acompanhe as&nbsp;<a href=\"https://make.wordpress.org/test/\">iniciativas de teste no Make Core</a>&nbsp;e junte-se ao&nbsp;<a href=\"https://wordpress.slack.com/messages/core-test/\">canal #core-test</a>&nbsp;no&nbsp;<a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Atualizações e destaques da versão Beta 5</h2>\n\n\n\n<p class=\"wp-block-paragraph\">O WordPress 7.0 Beta 5 contém mais de 101 atualizações e correções desde a versão do Beta 3.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Cada ciclo beta se concentra em correções de erros, e mais estão a caminho com sua ajuda através de testes. Você pode navegar pelos detalhes técnicos para todas as questões abordadas desde o Beta 3 usando esses links:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/7.0?since=2026-03-05&amp;until=2026-03-12\">Tíquetes do GitHub</a> desde 5 de março de 2026</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=03%2F05%2F2026..03%2F12%2F2026&amp;milestone=7.0&amp;group=component&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Tíquetes fechados do Trac</a> desde 5 de março de 2026</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Questões abordadas desde Beta 4:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/7.0?since=2026-03-10&amp;until=2026-03-12\">Tíquetes do GitHub</a> desde 10 de março de 2026</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=03%2F10%2F2026..03%2F12%2F2026&amp;milestone=7.0&amp;group=component&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Tíquetes fechados do Trac</a> desde 10 de março de 2026</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>WordPress 7.0 Beta 5 contém um novo recurso!</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Acesse instantaneamente todas as ferramentas que você precisa com um único clique usando o <strong>novo atalho de Paleta de Comando</strong>! Na versão 7.0 Beta 5, os editores logados verão um campo com um símbolo <code>⌘K</code> ou <code>Ctrl+K</code> na barra de administração superior que abre a paleta de comandos quando clicado. O novo ponto de entrada da paleta de comandos simplifica a navegação e a personalização, dando-lhe controle total de qualquer lugar do seu site, seja você editando, projetando ou apenas navegando em plugins.</p>\n\n\n\n<p class=\"has-text-align-right wp-block-paragraph\"><em>Agradecemos a <a href=\"https://profiles.wordpress.org/amykamala/\">@amykamala</a>, <a href=\"https://profiles.wordpress.org/annezazu/\">@annezazu</a> e <a href=\"https://profiles.wordpress.org/4thhubbard/\">@4thhubbard</a> para colaboração no <a href=\"https://wordpress.org/news/2026/03/wordpress-7-0-beta-5/\">post original</a>.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:62:\"https://br.wordpress.org/2026/03/12/wordpress-7-0-beta-5/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3446\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordPress 6.9.4 – Atualização de segurança\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://br.wordpress.org/2026/03/11/wordpress-6-9-4-atualizacao-de-seguranca/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 11 Mar 2026 16:01:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.9\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3442\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:364:\"WordPress 6.9.4 já está disponível! O WordPress 6.9.2 e o WordPress 6.9.3 foram lançados ontem, abordando 10 problemas de segurança e um erro que afetou o carregamento de arquivos de modelo em um número limitado de sites. A equipe de segurança do WordPress descobriu que nem todas as correções de segurança foram totalmente aplicadas, portanto, [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"Andre\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2514:\"\n<h2 class=\"wp-block-heading\">WordPress 6.9.4 já está disponível!</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://br.wordpress.org/2026/03/10/o-wordpress-6-9-2-atualizacao-de-seguranca/\">O WordPress 6.9.2</a> e o <a href=\"https://br.wordpress.org/2026/03/10/wordpress-6-9-3-e-7-0-beta-4/\">WordPress 6.9.3</a> foram lançados ontem, abordando 10 problemas de segurança e um erro que afetou o carregamento de arquivos de modelo em um número limitado de sites.</p>\n\n\n\n<p class=\"wp-block-paragraph\">A equipe de segurança do WordPress descobriu que nem todas as correções de segurança foram totalmente aplicadas, portanto, a versão 6.9.4 foi lançada contendo as correções adicionais necessárias.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Como este é um lançamento de segurança, <strong>é recomendável que você atualize seus sites imediatamente</strong>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Você pode <a href=\"https://wordpress.org/wordpress-6.9.4.zip\">baixar o WordPress 6.9.4 do WordPress.org</a> ou visitar seu Painel do WordPress, clicar em “Atualizações” e, em seguida, clicar em “Atualizar agora”. Se você tiver sites que suportam atualizações automáticas em segundo plano, o processo de atualização começará automaticamente.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Para mais informações sobre o WordPress 6.9.4, visite a <a href=\"https://wordpress.org/documentation/wordpress-version/version-6-9-4/\">página de versão no site do HelpHub</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Atualizações de segurança incluídas nesta versão</h2>\n\n\n\n<p class=\"wp-block-paragraph\">A equipe de segurança gostaria de agradecer aos contribuidores que relataram e investigaram estas questões, em particular a <a href=\"https://profiles.wordpress.org/kraftner\">Thomas Kräftner</a> por sua divulgação responsável. Os problemas de segurança que são resolvidos na versão 6.9.4 são:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Um problema de travessia de diretórios do PclZip relatado de forma independente por <a href=\"https://profiles.wordpress.org/francescocarlucci/\">Francesco Carlucci</a> e <a href=\"https://profiles.wordpress.org/kaminuma/\">kaminuma</a></li>\n\n\n\n<li>Um desvio de autorização no recurso Notas relatado pelo <a href=\"https://profiles.wordpress.org/kaminuma/\">kaminuma</a></li>\n\n\n\n<li>Um problema de XXE na biblioteca externa getID3 relatada por <a href=\"https://profiles.wordpress.org/regex33/\">Youssef Achtatal</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3442\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:63:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"WordPress 6.9.3 e 7.0 Beta 4\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:65:\"https://br.wordpress.org/2026/03/10/wordpress-6-9-3-e-7-0-beta-4/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 11 Mar 2026 00:32:47 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.9\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:3:\"7.0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3438\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:357:\"O WordPress 6.9.2 foi lançado hoje cedo e abordou 10 problemas de segurança. Alguns usuários relataram posteriormente um problema em que o frontend do site estava aparecendo em branco após a atualização para a versão 6.9.2. O problema foi identificado em alguns temas que usam uma abordagem incomum para carregar arquivos de modelo por meio [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"Andre\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5019:\"\n<p class=\"wp-block-paragraph\"><a href=\"https://br.wordpress.org/2026/03/10/o-wordpress-6-9-2-atualizacao-de-seguranca/\">O WordPress 6.9.2 foi lançado hoje cedo</a> e abordou 10 problemas de segurança.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Alguns usuários relataram posteriormente um problema em que o frontend do site estava aparecendo em branco após a atualização para a versão 6.9.2. O problema foi identificado em alguns temas que usam uma abordagem incomum para carregar arquivos de modelo por meio de “stringable objects” em vez de strings primitivas para caminhos de arquivo.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Embora esta não seja uma abordagem oficialmente suportada para carregar arquivos de modelo no WordPress (o filtro <code>template_include</code> só aceita uma string), no entanto, fez com que alguns sites tivessem este comportamento. Como resultado, a equipe de segurança decidiu resolver o problema em uma versão 6.9.3.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Como sempre, <strong>é recomendável que você atualize seus sites para a versão mais recente do WordPress imediatamente.</strong> Isso garante que seu site esteja protegido por todas as correções de segurança disponíveis na versão 6.9.2 e que você não será afetado pelo erro corrigido na versão 6.9.3.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Agradecemos aqueles que relataram, ajudaram a reproduzir e a resolver o problema.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Você pode <a href=\"https://wordpress.org/wordpress-6.9.3.zip\">baixar o WordPress 6.9.3 no WordPress.org</a> ou visitar seu Painel do WordPress, clicar em “Atualizações” e, em seguida, clicar em “Atualizar agora”. Se você tiver sites que suportam atualizações automáticas em segundo plano, o processo de atualização começará em breve. Você não precisa fazer nada!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Para mais informações sobre o <a href=\"https://wordpress.org/documentation/wordpress-version/version-6-9-3/\">WordPress 6.9.3</a>, visite a <a href=\"https://wordpress.org/documentation/wordpress-version/version-6-9-3/\">página da versão no site do HelpHub</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress 7.0 Beta 4</h2>\n\n\n\n<p class=\"wp-block-paragraph\">O próximo grande lançamento do WordPress será a <a href=\"https://make.wordpress.org/core/7-0/\">versão 7.0</a>, que está prevista para 9 de abril de 2026. A Equipe de Segurança decidiu empacotar um novo lançamento Beta (7.0 Beta 4) para manter todos protegidos contra as vulnerabilidades corrigidas, incluindo os membros dedicados da comunidade, concentrando seu tempo e esforço em testar o próximo lançamento.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Esta será uma versão Beta adicional no ciclo de lançamento 7.0.</strong> O cronograma permanecerá o mesmo daqui para frente, mas com cinco lançamentos Beta totais em vez dos quatro planejados anteriormente. O próximo lançamento Beta da versão 7.0 ainda está programado para quinta-feira, 12 de março.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Esta versão Beta do software WordPress ainda está em desenvolvimento</strong>. Não instale, execute ou teste versões Beta do WordPress em sites de produção ou de missão crítica. Em vez disso, você deve avaliar a versão Beta 4 em um servidor e site de testes.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Atualizações e destaques da versão Beta 4</h2>\n\n\n\n<p class=\"wp-block-paragraph\">O WordPress 7.0 Beta 4 contém as dez atualizações de segurança enviadas no WordPress 6.9.2 e mais de 49 atualizações e correções desde a versão Beta 3, incluindo 14 no editor e 35 no núcleo.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Cada ciclo Beta se concentra em correções de erros, e mais estão a caminho, graças à sua ajuda com os testes. Você pode navegar pelos detalhes técnicos para todas as questões abordadas desde a versão Beta 3 nestes links:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/compare/f4d8a5803aa2fbe26e7d9af4d17e80a622b7bab8...9b8144036fa5faf75de43d4502ff9809fcf689ad\">Tíquetes do GitHub para a versão 7.0</a> desde 5 de março de 2026</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=03%2F05%2F2026..03%2F10%2F2026&amp;milestone=7.0&amp;group=component&amp;col=id&amp;col=summary&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Tíquetes fechados do Trac para a versão 7.0</a> desde 5 de março de 2026</li>\n</ul>\n\n\n\n<p class=\"has-text-align-right wp-block-paragraph\">Agradecemos a <em><a href=\"https://profiles.wordpress.org/peterwilson/\">@peterwilson</a>, <a href=\"https://profiles.wordpress.org/desrosj/\">@desrosj</a>, <a href=\"https://profiles.wordpress.org/marybaum/\">@marybaum</a> e <a href=\"https://profiles.wordpress.org/amykamala/\">@amykamala</a> pela colaboração no <a href=\"https://wordpress.org/news/2026/03/wordpress-6-9-3-and-7-0-beta-4/\">post original</a>.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3438\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:49:\"O WordPress 6.9.2 – Atualização de segurança\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://br.wordpress.org/2026/03/10/o-wordpress-6-9-2-atualizacao-de-seguranca/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 10 Mar 2026 17:13:37 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.9\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3433\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:385:\"O WordPress 6.9.2 já está disponível! Esta é de uma versão de segurança que apresenta várias correções. Como este é um lançamento de segurança, é recomendável que você atualize seus sites imediatamente. Você pode baixar o WordPress 6.9.2 do WordPress.org ou visitar seu Painel do WordPress, clicar em “Atualizações” e, em seguida, clicar em “Atualizar [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"Andre\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5087:\"\n<p class=\"wp-block-paragraph\">O WordPress 6.9.2 já está disponível! Esta é  de uma versão de segurança que apresenta várias correções. Como este é um lançamento de segurança, <strong>é recomendável que você atualize seus sites imediatamente</strong>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Você pode <a href=\"https://wordpress.org/wordpress-6.9.2.zip\">baixar o WordPress 6.9.2 do WordPress.org</a> ou visitar seu Painel do WordPress, clicar em “Atualizações” e, em seguida, clicar em “Atualizar agora”. Se você tiver sites que suportam atualizações automáticas em segundo plano, o processo de atualização começará automaticamente.</p>\n\n\n\n<p class=\"wp-block-paragraph\">O próximo grande lançamento será a <a href=\"https://make.wordpress.org/core/7-0/\">versão 7.0</a>, que está prevista para 9 de abril de 2026.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Para mais informações sobre o <a href=\"https://wordpress.org/documentation/wordpress-version/version-6-9-2/\">WordPress 6.9.2</a>, visite a <a href=\"https://wordpress.org/documentation/wordpress-version/version-6-9-2/\">página de versão no site do HelpHub</a> (em inglês).</p>\n\n\n\n<h2 class=\"wp-block-heading\">Atualizações de segurança incluídas nesta versão</h2>\n\n\n\n<p class=\"wp-block-paragraph\">A equipe de segurança gostaria de agradecer às seguintes pessoas por <a href=\"https://hackerone.com/wordpress?type=team\">relatar com responsabilidade as vulnerabilidades</a> e permitir que elas sejam corrigidas nesta versão:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Um problema de SSRF relatado por <a href=\"https://hackerone.com/sibwtf\">sibwtf</a> e, posteriormente, por vários outros pesquisadores enquanto a correção estava sendo trabalhada.</li>\n\n\n\n<li>Uma vulnerabilidade da cadeia PoP da API HTML e no Registro de Blocos relatado por <a href=\"https://github.com/hackerlo2003\">Phat RiO</a>.</li>\n\n\n\n<li>Uma vulnerabilidade de DoS Regex em referências de caracteres numéricos relatadas por Dennis Snell da Equipe de Segurança do WordPress</li>\n\n\n\n<li>Um problema de XSS em menus de navegação relatados por <a href=\"https://x.com/Savphill\">Phill Savage</a></li>\n\n\n\n<li>Um  problema de autorização com <code>Ajax query-attachments</code> reportado por <a href=\"https://www.vitalysim.com/\">Vitaly Simonovich</a>.</li>\n\n\n\n<li>Um problema de XSS através do <code>data-wp-bind</code> reportado por <a href=\"https://profiles.wordpress.org/kaminuma/\">kaminuma</a></li>\n\n\n\n<li>Um problema de XSS que permite substituir os modelos do lado do cliente na área de administração, relatada pelo <a href=\"https://hackerone.com/amosec\">Asaf Mozes</a></li>\n\n\n\n<li>Um problema de travessia de diretórios do PclZip relatado de forma independente por <a href=\"https://profiles.wordpress.org/francescocarlucci/\">Francesco Carlucci</a> e <a href=\"https://profiles.wordpress.org/kaminuma/\">kaminuma</a></li>\n\n\n\n<li>Um desvio de autorização no recurso de notas relatado por <a href=\"https://profiles.wordpress.org/kaminuma/\">kaminuma</a></li>\n\n\n\n<li>Um problema na biblioteca XXE externa <code>getID3</code> relatada por <a href=\"https://profiles.wordpress.org/regex33/\">Youssef Achtatal</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">A equipe de segurança do WordPress trabalhou com o mantenedor da biblioteca externa getID3, James Heinrich, para coordenar uma correção para o getID3. Uma nova versão do getID3 <a href=\"https://github.com/JamesHeinrich/getID3/releases\">está disponível aqui</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Como cortesia, essas correções estão sendo suportadas, quando necessário, para todas as versões anteriores elegíveis para receber correções de segurança (atualmente até a versão 4.7). Como lembrete, <strong>apenas a versão mais recente do WordPress é ativamente suportada</strong>. Os backports estão em andamento e serão enviados à medida que se tornam prontos.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Agradecimento aos colaboradores</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Este lançamento foi liderado por <a href=\"https://profiles.wordpress.org/johnbillion/\">John Blackbourn</a>. Além dos pesquisadores de segurança mencionados acima, o WordPress 6.9.2 não teria sido possível sem as contribuições das seguintes pessoas: <a href=\"https://profiles.wordpress.org/dmsnell/\">Dennis Snell</a>, <a href=\"https://profiles.wordpress.org/xknown/\">Alex Concha</a>, <a href=\"https://profiles.wordpress.org/jonsurrell/\">Jon Surrell</a>, <a href=\"https://profiles.wordpress.org/isabel_brison/\">Isabel Brison</a>, <a href=\"https://profiles.wordpress.org/peterwilsoncc/\">Peter Wilson</a>, <a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a>, <a href=\"https://profiles.wordpress.org/audrasjb/\">Jb Audras</a>, <a href=\"https://profiles.wordpress.org/luisherranz/\">Luis Herranz</a>, <a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/westonruter/\">Weston Ruter</a> e <a href=\"https://profiles.wordpress.org/ocean90/\">Dominik Schilling</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3433\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"WordPress 7.0 Beta 3\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://br.wordpress.org/2026/03/05/wordpress-7-0-beta-3/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 05 Mar 2026 14:48:28 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"7.0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3428\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:326:\"O WordPress 7.0 Beta 3 está disponível para baixar e testar! Esta versão beta do software WordPress ainda está em desenvolvimento. Por favor, não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica. Em vez disso, você deve avaliar o Beta 3 em um servidor e site de [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"Andre\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5739:\"\n<p class=\"wp-block-paragraph\">O WordPress 7.0 Beta 3 está disponível para baixar e testar!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Esta versão beta do software WordPress ainda está em desenvolvimento</strong>. Por favor, não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica. Em vez disso, você deve avaliar o Beta 3 em um servidor e site de teste.</p>\n\n\n\n<p class=\"wp-block-paragraph\">O WordPress 7.0 Beta 3 pode ser testado usando qualquer um dos seguintes métodos:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>Plugin</strong></td><td>Instale e ative o plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> em uma instalação <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">do</a> WordPress. (Selecione o canal “Bleeding edge” e “Beta/RC Only” stream.)</td></tr><tr><td><strong>Baixe diretamente</strong></td><td>Baixe a <a href=\"https://wordpress.org/wordpress-7.0-beta3.zip\">versão Beta 3 (zip)</a> e instale-a em um site WordPress.</td></tr><tr><td><strong>Linha de Comando</strong></td><td>Use este <a href=\"https://make.wordpress.org/cli/\">comando do WP-CLI</a>:<br><code>wp core update --version=7.0-beta</code>3</td></tr><tr><td><strong>WordPress Playground</strong></td><td>Use a <a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\">instância do WordPress Playground</a> para testar o software diretamente no seu navegador. Nenhuma configuração é necessária, basta clicar e testar!</td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\">A data de lançamento final programada para o WordPress 7.0 é <strong>9 de abril de 2026</strong>. O <a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">cronograma de lançamento</a> completo <a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">pode ser encontrado aqui</a>. Sua ajuda para testar versões Beta e RC é vital para tornar esta versão o mais estável e poderosa possível. Certifique-se de acompanhar o <a href=\"https://make.wordpress.org/core/\">blog Make WordPress Core</a> para <a href=\"https://make.wordpress.org/core/tag/7-0\">posts relacionadas a versão 7.0</a> nas próximas semanas para obter mais informações. Agradecemos a todos que contribuem testando!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Acompanhe o que há de novo no WordPress 7.0</strong>: Leia <a href=\"https://br.wordpress.org/2026/02/20/wordpress-7-0-beta-1/\">o anúncio da versão Beta 1</a> para obter mais detalhes e destaques.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Como testar esta versão</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Sua ajuda testando o WordPress 7.0 Beta 2 é fundamental para garantir que tudo na versão seja o melhor possível. Embora testar o processo de atualização seja essencial, experimentar novos recursos é igualmente importante. Este <a href=\"https://make.wordpress.org/test/2026/02/20/help-test-wordpress-7-0/\">guia sobre o que testar no WordPress 7</a> irá guiá-lo através de recursos de teste na versão 7.0.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Se você encontrar um problema, compartilhe-o na <a href=\"https://wordpress.org/support/forum/alphabeta/\">área Alpha/Beta</a> dos fóruns de suporte ou diretamente <a href=\"https://core.trac.wordpress.org/newticket\">para o WordPress Trac</a>, se você estiver confortável escrevendo um relatório de erros reproduzível. Você também pode verificar seu problema em uma lista de <a href=\"https://core.trac.wordpress.org/tickets/major\">erros conhecidos</a>. Curioso sobre os lançamentos de testes em geral? Acompanhe as <a href=\"https://make.wordpress.org/test/\">iniciativas de teste no Make Core</a> e junte-se ao <a href=\"https://wordpress.slack.com/messages/core-test/\">canal #core-test</a> no <a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Atualizações e destaques</h2>\n\n\n\n<p class=\"wp-block-paragraph\">O WordPress 7.0 Beta 3 contém mais de 95 atualizações e correções desde a versão Beta 2, incluindo 43 no editor e 52 no núcleo.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Cada ciclo beta se concentra em correções de erros, e mais estão a caminho com sua ajuda através de testes. Você pode navegar pelos detalhes técnicos para todas as questões abordadas desde a versão Beta 2 usando esses links:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/7.0?since=2026-02-26&amp;until=2026-03-05\">Tíquetes do GitHub para a versão 7.0</a> desde 26 de fevereiro de 2026.</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=02%2F26%2F2026..03%2F05%2F2026&amp;milestone=7.0&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Tíquetes fechados do Trac para a versão 7.0</a> desde 26 de fevereiro de 2026.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Explorar o poder da IA está ainda mais fácil na versão Beta 3! A tela do <code>WP AI Client Connectors</code> agora registra provedores dinamicamente, além dos 3 provedores padrão, dando aos usuários mais flexibilidade e comandos para as integrações de IA.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Agradecemos a <a href=\"https://profiles.wordpress.org/annezazu/\">@annezazu</a></em>, <em><a href=\"https://profiles.wordpress.org/jeffpaul/\">@jeffpaul</a></em> e <em><a href=\"https://profiles.wordpress.org/chaion07/\">@chaion07</a></em> <em>pela colaboração no post original.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3428\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:57:\"\n		\n		\n		\n		\n		\n				\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:66:\"O piloto do painel do colaborador está no ar: o que vem a seguir?\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"https://br.wordpress.org/2026/03/05/o-piloto-do-painel-do-colaborador-esta-no-ar-o-que-vem-a-seguir/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 05 Mar 2026 13:23:37 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"Geral\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3417\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:355:\"O piloto do painel do colaborador está no ar, marcando um passo importante para criar uma visão mais clara de como os colaboradores se juntam, participam e crescem em todo o projeto WordPress. Este post descreve os recursos propostos para a próxima fase do piloto do painel do colaborador. Estamos compartilhando essas ideias previamente para [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"Andre\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6355:\"\n<p class=\"wp-block-paragraph\">O piloto do painel do colaborador está no ar, marcando um passo importante para criar uma visão mais clara de como os colaboradores se juntam, participam e crescem em todo o projeto WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Este post descreve os recursos propostos para a próxima fase do piloto do painel do colaborador. Estamos compartilhando essas ideias previamente para coletar feedback da comunidade antes do início da implementação.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Sobre o projeto</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">O objetivo do painel é mapear a atividade dos contribuidores entre equipes em um framework compartilhado chamado escada de colaboração.</p>\n\n\n\n<p class=\"wp-block-paragraph\">A escada é baseada em comportamentos e descreve padrões de participação ao longo do tempo. Ela não classifica contribuidores nem implica que alguns tipos de contribuição sejam mais importantes que outros. Todos os tipos de contribuição e todos os contribuidores importam.</p>\n\n\n\n<p class=\"wp-block-paragraph\">O objetivo é ajudar as equipes a compreenderem os padrões de participação, identificar onde pode ser necessário oferecer suporte e melhorar as experiências dos contribuidores ao longo do tempo.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Status atual</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>O painel piloto está finalmente disponível: <a href=\"https://wpcontributordashboard.org/\">https://wpcontributordashboard.org/</a></strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">As funcionalidades principais disponíveis:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Arquitetura de dados de três níveis (Eventos <span aria-hidden=\"true\" class=\"wp-exclude-emoji\">→</span> Perfis <span aria-hidden=\"true\" class=\"wp-exclude-emoji\">→</span> Painel)</li>\n\n\n\n<li>Estrutura da escalada do colaborador</li>\n\n\n\n<li>Acompanhamento de status de atividade (ativo/ausente/inativo)</li>\n\n\n\n<li>Sistema de importação CSV para dados de atividades do colaborador</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">O desenvolvimento está acontecendo no <a href=\"https://github.com/WordPress/wporg-contributor-dashboard\">repositório público do GitHub</a>.<br><a href=\"https://cleanshot.com/share/hkpxHJjc\">Veja o vídeo de demonstração do painel aqui.</a></p>\n\n\n\n<p class=\"wp-block-paragraph\">Colaboradores de várias equipes do Make WordPress estão envolvidos no desenvolvimento o piloto do painel do colaborador. Colaboradores do projeto incluem <a href=\"https://profiles.wordpress.org/felipevelzani/\">@felipevelzani</a>, <a href=\"https://profiles.wordpress.org/unintended8/\">@unintentiond8</a>, <a href=\"https://profiles.wordpress.org/francescodicandia/\">@francescodicandia</a>, <a href=\"https://profiles.wordpress.org/dd32/\">@dd32</a> e <a href=\"https://profiles.wordpress.org/kel-dc/\">@ kel-dc</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Características Propostas</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">Estamos propondo duas características para a próxima fase. O feedback é bem-vindo em ambos.</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>1. 1. Personas Gerenciadas por Equipe</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Cada equipe do Make WordPress pode criar suas próprias personas de contribuição, com escaladas e requisitos personalizados que refletem como essa equipe realmente funciona.</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Equipes diferentes contribuem de maneiras diferentes, uma escalada não se encaixa em todas. Os representantes da equipe podem definir e gerenciar essas personas, e os colaboradores podem aparecer em várias escaladas com base em sua atividade entre as equipes.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Exemplo de casos de uso:</strong></p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Os Polyglots podem criar personas específicas de idiomas para colaboradores de tradução.</li>\n\n\n\n<li>Comunidade pode criar personas para os organizadores do WordCamp ou Meetup.</li>\n\n\n\n<li>O suporte pode separar os colaboradores do fórum daqueles que procuram ajuda.</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>2. 2. Engajamento Automatizado</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Reconhecer automaticamente os colaboradores quando atingirem os principais marcos.</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">O reconhecimento oportuno melhora a retenção e reforça a participação significativa. Quando alguém faz sua primeira contribuição, atinge um novo degrau da escalada, ou permanece consistentemente ativo, o sistema pode acionar mensagens, adereços, ou até mesmo swag (adesivos, etc) de <a href=\"https://mercantile.wordpress.org/\">O Mercantil</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">O reconhecimento torna-se incorporado, não manual.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Feedback Solicitado</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">Gostaríamos muito de ouvir seus pensamentos sobre essas propostas. Se tivéssemos que começar com um desses dois, qual forneceria mais valor? Algum outro recurso que você considere importante deva ser implementado e/ou poderia trazer muito valor?</p>\n\n\n\n<p class=\"wp-block-paragraph\">O objetivo geral é criar um motor focado em melhorar a experiência do colaborador em geral.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Compartilhe qualquer feedback até <strong>17</strong> de <strong>março de 2026. </strong>Planejamos começar a implementar a nova fase até esta data.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Envolva-se</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">Se você estiver interessado em contribuir para esses recursos:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Comente neste post com feedback ou perguntas no <a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\">post original</a>.</li>\n\n\n\n<li>Junte-se à discussão no canal <a href=\"https://wordpress.slack.com/archives/C0AHJA81PDE\">#contribuinte-dashboard</a> no Slack.</li>\n\n\n\n<li>Confira o <a href=\"https://make.wordpress.org/handbook/contributor-dashboard/\">Manual do Painel do Colaborador</a> e o <a href=\"https://github.com/WordPress/wporg-contributor-dashboard\">repositório do GitHub</a> para obter detalhes técnicos e contribuir com o grupo de trabalho.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3417\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"WordPress 7.0 Beta 2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://br.wordpress.org/2026/02/26/wordpress-7-0-beta-2/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 26 Feb 2026 17:20:12 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"7.0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3408\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:120:\"O WordPress 7.0 Beta 2 contém mais de 70 atualizações e correções no editor e no núcleo desde a versão do Beta 1.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"Andre\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7358:\"\n<p class=\"wp-block-paragraph\">O WordPress 7.0 Beta 2 já está pronto para testes!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Esta versão beta do software WordPress está em desenvolvimento</strong>. Não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica. Em vez disso, você deve avaliar a versão Beta 2 em um servidor e site de teste. Você pode testar o WordPress 7.0 Beta 2 de qualquer uma das seguintes maneiras:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>Plugin</strong></td><td>Instale e ative o plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> em uma instalação do WordPress. (Selecione o canal “Bleeding edge” e “Beta/RC Only” stream.)</td></tr><tr><td><strong>Baixe diretamente</strong></td><td>Baixe a <a href=\"https://wordpress.org/wordpress-7.0-beta2.zip\">versão Beta 2 (zip)</a> e instale-a em um site WordPress.</td></tr><tr><td><strong>Linha de Comando</strong></td><td>Use este comando do <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a> WP-CLI:<br><code>wp core update --version=7.0-beta2</code></td></tr><tr><td><strong>WordPress Playground</strong></td><td>Use uma <a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\">instância do WordPress Playground</a> para testar o software diretamente no seu navegador. Nenhuma configuração é necessária – basta clicar e testar!</td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\">A data de lançamento final programada para o WordPress 7.0 é <strong>9 de abril de 2026</strong>. O <a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">cronograma de lançamento</a> completo <a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">pode ser encontrado aqui</a>. Sua ajuda para testar versões Beta e RC é vital para tornar esta versão o mais estável e poderosa possível. Certifique-se de acompanhar o <a href=\"https://make.wordpress.org/core/\">blog Make WordPress Core</a> para <a href=\"https://make.wordpress.org/core/tag/7-0\">posts relacionadas a versão 7.0</a> nas próximas semanas para obter mais informações. Agradecemos a todos que contribuem testando!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Acompanhe o que há de novo no WordPress 7.0</strong>: Leia <a href=\"https://br.wordpress.org/2026/02/20/wordpress-7-0-beta-1/\">o anúncio da versão Beta 1</a> para obter mais detalhes e destaques.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Como testar esta versão</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Sua ajuda testando o WordPress 7.0 Beta 2 é fundamental para garantir que tudo na versão seja o melhor possível. Embora testar o processo de atualização seja essencial, experimentar novos recursos é igualmente importante. Este <a href=\"https://make.wordpress.org/test/2026/02/20/help-test-wordpress-7-0/\">guia sobre o que testar no WordPress 7</a> irá guiá-lo através de recursos de teste na versão 7.0.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Se você encontrar um problema, compartilhe-o na <a href=\"https://wordpress.org/support/forum/alphabeta/\">área Alpha/Beta</a> dos fóruns de suporte ou diretamente <a href=\"https://core.trac.wordpress.org/newticket\">para o WordPress Trac</a>, se você estiver confortável escrevendo um relatório de erros reproduzível. Você também pode verificar seu problema em uma lista de <a href=\"https://core.trac.wordpress.org/tickets/major\">erros conhecidos</a>. Curioso sobre os lançamentos de testes em geral? Acompanhe as <a href=\"https://make.wordpress.org/test/\">iniciativas de teste no Make Core</a> e junte-se ao <a href=\"https://wordpress.slack.com/messages/core-test/\">canal #core-test</a> no <a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Beta 2 atualizações e destaques</h2>\n\n\n\n<p class=\"wp-block-paragraph\">O WordPress 7.0 Beta 2 contém mais de 70 atualizações e correções no editor e no núcleo desde a versão do Beta 1.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Cada ciclo beta se concentra em correções de erros, e mais estão a caminho com sua ajuda através de testes. Você pode navegar pelos detalhes técnicos para todas as questões abordadas desde o Beta 1 usando estes links:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/7.0?since=2026-02-20&amp;until=2026-02-26\">Tíquetes do GitHub para a versão 7.0</a> desde 20 de fevereiro de 2026.</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=02%2F20%2F2026..02%2F26%2F2026&amp;milestone=7.0&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Tíquetes fechados do Trac para a versão 7.0</a> desde 20 de fevereiro de 2026.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>A versão Beta 2 também contém um novo recurso!</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">O gerenciamento do provedor de IA é mais intuitivo no 7.0 Beta 2 com uma nova página de painel de interface do usuário do Connectors. Os usuários do WordPress agora podem gerenciar conexões de IA externas em um local central no painel, em Configurações &gt; Conectores. A nova interface do usuário permite que os usuários adicionem, excluam e atualizem conexões externas. Ele é alimentado por uma arquitetura extensível e baseada em rotas que permite que plugins e temas se encaixem na página e expandam sua funcionalidade. A nova página Conectores é baseada em infraestrutura de script e menu baseada em PHP e adiciona componentes de rota alimentados por <code>@wordpress/components</code> e <code>@wordpress/admin-ui</code>. Um novo hook <code>connections-wp-admin-init</code> e uma nova API de registros permitem que os plugins se integrem de forma limpa. Isso facilita o gerenciamento de conexões externas, dando aos desenvolvedores um caminho mais claro para estender a experiência.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Atenção, criadores de blocos!</strong> O WordPress 7.0 impõe o editor detalhado para temas clássicos quando todos os blocos usam a API de blocos versão 3. Atualize seus blocos para a versão 3 para garantir a compatibilidade. Mais detalhes sobre o <a href=\"https://make.wordpress.org/core/2026/02/24/iframed-editor-changes-in-wordpress-7-0/\">Iframed Editor Changes no WordPress 7.0 aqui</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Gutenberg 22.6</strong>, lançado em 25 de fevereiro, também será aplicado no WordPress 7.0. Aqui estão mais detalhes sobre <a href=\"https://make.wordpress.org/core/2026/02/25/whats-new-in-gutenberg-22-6-25-february/\">o que há de novo em Gutenberg 22.6</a>.</p>\n\n\n\n<p class=\"has-text-align-right wp-block-paragraph\"><em>Agradecemos a <a href=\"https://profiles.wordpress.org/4thhubbard/\">@4thhubbard</a>, <a href=\"https://profiles.wordpress.org/annezazu/\">@annezazu</a></em>, <em><a href=\"https://profiles.wordpress.org/audrasjb/\">@audrasjb</a>, <a href=\"https://profiles.wordpress.org/mukesh27/\">@mukesh27</a> e <a href=\"https://profiles.wordpress.org/chaion07/\">@chaion07</a></em> <em>pela colaboração no post original.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3408\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:35:\"https://br.wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s